struct PStep { int note; int on; int slide; int accent; };
struct PPattern {
    PStep steps[16];
    double bpm;
    PPattern() : bpm(120.0) { for (int i = 0; i < 16; ++i) steps[i] = {36,1,0,0}; }
    PPattern(const std::array<int,16>& n, const std::array<int,16>& o,
             const std::array<int,16>& sl, const std::array<int,16>& ac, double b) {
        for (int i = 0; i < 16; ++i) { steps[i].note = n[i]; steps[i].on = o[i]; steps[i].slide = sl[i]; steps[i].accent = ac[i]; }
        bpm = b;
    }
};
